const input = $input.first().json;
const { run_id, module, scope, metro_id, opportunity_id, query_profile, callback_url } = input;

const orgName = query_profile?.organization || '';
const metro = query_profile?.metro || '';
const grantVectors = query_profile?.knowledge?.grant_alignment_vectors || {};

const queries = [];

if (scope === 'opportunity' && orgName) {
  queries.push(`${orgName} grant funding opportunity`);
  queries.push(`digital equity broadband grant ${orgName} eligible`);
  queries.push(`technology nonprofit grant deadline 2025 2026 ${orgName}`);
} else if (scope === 'metro' && metro) {
  queries.push(`${metro} digital equity broadband grant funding 2025 2026`);
  queries.push(`${metro} nonprofit technology infrastructure grant`);
  queries.push(`${metro} community development grant opportunity deadline`);
}

if (queries.length === 0) {
  queries.push('digital equity broadband nonprofit grant funding 2025 2026');
}

return queries.map((q, i) => ({
  json: { run_id, module, scope, metro_id, opportunity_id, callback_url, query: q, query_index: i, limit: 10 }
}));

const allItems = $input.all();
const seenUrls = new Set();
const results = [];

for (const item of allItems) {
  const data = item.json?.data || item.json?.results || [];
  if (!Array.isArray(data)) continue;
  for (const r of data) {
    const url = (r.url || r.sourceUrl || '').toLowerCase().trim();
    if (!url || seenUrls.has(url)) continue;
    seenUrls.add(url);
    results.push({
      url: r.url || r.sourceUrl || '',
      title: r.title || r.metadata?.title || '',
      snippet: r.markdown?.substring(0, 500) || r.description || '',
      source: r.metadata?.sourceURL || url
    });
  }
}

const ctx = $input.first()?.json || {};
return [{ json: { run_id: ctx.run_id, module: ctx.module, scope: ctx.scope, metro_id: ctx.metro_id, opportunity_id: ctx.opportunity_id, callback_url: ctx.callback_url, results, result_count: results.length } }];

