const mergeData = $node['Merge & Pre-Filter'].json;
const extractRaw = $node['LLM Extract Grants'].json?.message?.content || '{"grants":[]}';
const briefingRaw = $node['LLM Briefing'].json?.message?.content || '{}';

let extracted = { grants: [] };
try { extracted = JSON.parse(extractRaw); } catch(e) { extracted = { grants: [] }; }

let briefingJson = {};
try { briefingJson = JSON.parse(briefingRaw); } catch(e) { briefingJson = { highlights: [], urgent: [], new_items: [], what_changed: [], gaps_and_next_queries: [], helpful_sources: [] }; }

const items = (extracted.grants || []).map(g => ({
  canonical_url: g.url || `grant:${(g.name||'unknown').toLowerCase().replace(/\s+/g, '-')}`,
  source_url: g.url || null,
  title: g.name || 'Unknown Grant',
  snippet: g.summary || '',
  organization_name: g.funder || null,
  published_date: g.deadline || null,
  extracted: g
}));

const lines = ['# Grants Discovery Briefing\n'];
if (briefingJson.highlights?.length) {
  lines.push('## Highlights');
  briefingJson.highlights.forEach(h => lines.push(`- **${h.title}**: ${h.why_it_matters}`));
  lines.push('');
}
if (briefingJson.urgent?.length) {
  lines.push('## ⚡ Urgent (Deadlines Soon)');
  briefingJson.urgent.forEach(u => lines.push(`- **${u.title}** (${u.date_info || 'soon'}): ${u.why_this_week}`));
  lines.push('');
}
if (briefingJson.new_items?.length) {
  lines.push('## New Grants');
  briefingJson.new_items.forEach(n => lines.push(`- **${n.title}**: ${n.one_liner}`));
  lines.push('');
}

return [{ json: {
  run_id: mergeData.run_id,
  status: 'completed',
  module: 'grants',
  scope: mergeData.scope,
  metro_id: mergeData.metro_id || null,
  opportunity_id: mergeData.opportunity_id || null,
  items,
  briefing_json: briefingJson,
  briefing_md: lines.join('\n'),
  stats: { search_results: mergeData.result_count || 0, grants_extracted: items.length }
} }];
